## Step-by-step Deobfuscation

The code uses a common obfuscation pattern with:
1. **A string array** (`a0_0x4453`) containing base64-encoded strings
2. **A decoder function** (`a0_0x305b`) that decodes base64 strings with caching
3. **An array shuffler** IIFE that rotates the string array until a checksum matches
4. **Hex number literals** and mangled variable names throughout

## Deobfuscated Code

```javascript
// Constants
const TAU = 6.283;          // ~2π
const PHI = 1.618;          // Golden ratio
const SQRT1_2 = 0.707;      // ~√(1/2)

// Physics/simulation config
const config = {
  repulsionStrength: 4000,
  frictionCoeff: 0.004,
  amplitudeDamping: 0.92,
  dispersal: 0.0003,
  streamMax: 40,
  viscosity: 0.04,
  easing: 0.06
};

// --- NODES (graph vertices) ---
const nodes = [
  { id: "hub",     label: "Hub",     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// --- EDGES (spring connections) ---
const edges = [
  { a: "hub",   b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub",   b: "beta",    rest: 160, k: 0.005 },
  { a: "hub",   b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub",   b: "delta",   rest: 170, k: 0.004 },
  { a: "hub",   b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera / viewport state
let camera = { x: 400, y: 300, zoom: 1 };
let cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle stream
let particles = [];
let frameCount = 0;

// Find a node by ID
function findNode(id) {
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// --- PHYSICS: Apply forces ---
function applyForces() {
  // 1) Node-node REPULSION (Coulomb-like)
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      let dx = nodes[i].x - nodes[j].x;
      let dy = nodes[i].y - nodes[j].y;
      let dist = Math.sqrt(dx * dx + dy * dy) || 1;
      let force = config.repulsionStrength / (dist * dist);
      let fx = (dx / dist) * force;
      let fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Edge SPRING attraction (Hooke's law)
  for (let i = 0; i < edges.length; i++) {
    let nodeA = findNode(edges[i].a);
    let nodeB = findNode(edges[i].b);
    if (!nodeA || !nodeB) continue;
    let dx = nodeB.x - nodeA.x;
    let dy = nodeB.y - nodeA.y;
    let dist = Math.sqrt(dx * dx + dy * dy) || 1;
    let displacement = dist - edges[i].rest;
    let force = (edges[i].k || config.frictionCoeff) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) CENTER GRAVITY + velocity damping + position update
  for (let i = 0; i < nodes.length; i++) {
    nodes[i].vx += (400 - nodes[i].x) * config.dispersal;
    nodes[i].vy += (300 - nodes[i].y) * config.dispersal;
    nodes[i].vx *= config.amplitudeDamping;
    nodes[i].vy *= config.amplitudeDamping;
    nodes[i].x += nodes[i].vx;
    nodes[i].y += nodes[i].vy;
  }
}

// --- PARTICLE EMITTER ---
function emitParticle() {
  if (particles.length >= config.streamMax) return;

  // Pick a random node as spawn point
  let source = nodes[Math.floor(Math.random() * nodes.length)];
  let angle = Math.random() * TAU;
  let speed = 0.3 + Math.random() * SQRT1_2;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * SQRT1_2
  });
}

// --- PARTICLE UPDATE ---
function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    let p = particles[i];
    p.vx *= 1 - config.viscosity * 0.125;
    p.vy *= 1 - config.viscosity * 0.125;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

// --- CAMERA EASING ---
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.easing;
  camera.y += (cameraTarget.y - camera.y) * config.easing;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.easing;
}

// --- MAIN LOOP ---
function tick() {
  applyForces();
  frameCount++;
  updateParticles();
  if (frameCount % 3 === 0) emitParticle();
  updateCamera();
}

setInterval(tick, 16); // ~60 FPS
```

## What It Does

This is a **force-directed graph simulation** — the physics engine behind a network visualization (without the rendering/drawing code). Specifically:

| Component | Purpose |
|---|---|
| **Nodes** | 6 labeled nodes ("Hub", "Alpha", "Beta", "Gamma", "Delta", "Epsilon") arranged in a hub-and-spoke topology |
| **Repulsion** | All nodes repel each other (inverse-square law, like charged particles) to prevent overlap |
| **Spring Edges** | Connected nodes are pulled toward each other via Hooke's Law springs with configurable rest lengths and stiffness |
| **Center Gravity** | A weak force pulls all nodes toward center (400, 300) to prevent drift |
| **Damping** | Velocity is multiplied by 0.92 each frame to dissipate energy |
| **Particles** | Decorative particles spawn from random nodes, drift outward with friction, and die after a lifespan — creating a "streaming" visual effect |
| **Camera** | Smooth easing toward a target position/zoom (though the target is never changed in this snippet) |
| **Main Loop** | Runs at ~60 FPS via `setInterval(..., 16)` |

**In short:** It's the simulation/physics backend for an animated, interactive node-link diagram with decorative particle effects — likely rendered elsewhere on an HTML Canvas or SVG.
